var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"아카데미 클래스 관찰기록부 #001     \\n교육생 성명: <color=#ffd34c>한소림</color>     ","JPN":"アカデミークラス観察記録 #001     \\n教育生徒名：<color=#ffd34c>ハネダ・ミズキ</color>     ","ENG":"[[","TWN":"學院觀察記錄簿 #001     \\n學生 姓名: <color=#ffd34c>琳</color>","THA":"บันทึกการสังเกตการณ์ในชั้นเรียนของวิทยาลัย #001     \\nชื่อนักเรียน: <color=#ffd34c>ฮัน โซริม</color>     ","VTN":"Hồ Sơ Quan Sát Lớp Học Viện #001 \\nTên Học Viên: <color=#ffd34c>Han Sorim</color>","SCN":"学院观察记录簿 #001     \\n学生 姓名: <color=#ffd34c>小琳</color>     ","DEU":"Akademie\xA0– Klassenbeobachtungsprotokoll #001     \\nName: <color=#ffd34c>Han Sorim</color>     ","FRA":"Dossier d'observation de classe de l'Académie #001     \\nNom de l'élève\xA0: <color=#ffd34c>Han Sorim</color>     "},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"TEACHER_EXTRA_F_NULL","text":{"KOREA":"자, 오늘은 새로운 입학생이 왔어요.","JPN":"今日は、新入生が来てくれています。","ENG":"Alright, we have a new student today.","TWN":"那麼，今天我們來了一位新同學。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"TEACHER_EXTRA_F_NULL","text":{"KOREA":"소림 양? 우리, 자기소개를 해 볼까요?","JPN":"さあ、ハネダさん。自己紹介をどうぞ。","ENG":"Sorim? Will you introduce yourself?","TWN":"韓蕭林同學？做一下自我介紹吧。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"흠. 흠. 반갑다, 아카데미 동기생 여러분.","JPN":"う、うむ。お初にお目にかかる。アカデミーの同期諸君。","ENG":"Ahem. Ahem. It's nice to meet you, fellow Academy students.","TWN":"哼嗯，哼嗯。很高興見到你們，學院的各位同學們。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"본관은 애니멀 래스큐 스페셜포스 팀.","JPN":"本官はアニマル・レスキュースペシャルフォース、","ENG":"I come from the Animal Rescue Special Force Team,","TWN":"本官在動物救助特種部隊……"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"통칭 A.R.S 화이트 래빗에서 사격술고문으로 활동 중인 베테랑 솔저, 한소림 병장이다.","JPN":"通称A.R.Sホワイトラビットに射撃術顧問として務めている\\nベテランソルジャー、ハネダ・ミズキ兵長である。","ENG":"a.k.a. A.R.S. White Rabbit. I am Sergeant Han Sorim, a veteran soldier and also the marksmanship adviser.","TWN":"通稱A.R.S白兔社中，擔當射擊技術顧問的退役軍人，韓蕭林兵長。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"기초의무교육 수료를 위해 잠시 이곳에서 신세를 지게 되었으니 당분간 잘 부탁한다.","JPN":"基礎義務教育を修了すべく、しばらくここで厄介になる予定だ。以後よろしく頼む。","ENG":"I have been assigned to this facility to complete my compulsory education. I look forward to my time spent here.","TWN":"為了完成基礎義務教育，會在這裡暫時受到大家照顧，還請大家多多指教。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"STUDENT_EXTRA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"STUDENT_EXTRA_NULL_NULL","text":{"KOREA":"저, 정말 군인인가?","JPN":"ほ、本当に軍人さんなのかな？","ENG":"I-is she a real soldier?","TWN":"妳、妳真的是軍人嗎？"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"STUDENT_EXTRA_NULL_NULL","text":{"KOREA":"에이, 그럴 리가...... 군인은 어른들이 하는 거잖아.","JPN":"んなわけねえって……軍人はみんな大人だろ？","ENG":"Nah, that can't be true... Soldier is a job for adults.","TWN":"不會吧……軍人不是大人做的事情嗎？"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"비록 이곳에 배움을 얻으러 오긴 했지만 가르침을 나누는 것도 베테랑 솔저의 의무.","JPN":"学びを求めてここに来た身ではあるが、知識を分かち合うことも\\nベテランソルジャーたる者の務めである。","ENG":"Although I have come to learn, it is the responsibility of a veteran to share the knowledge as well.","TWN":"雖然我是為了學習才來到這裡，但和大家分享知識也是退役軍人的義務。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"혹시라도 총기조립이나 파지법, 야전 전투술에 대해 궁금한 사람이 있다면 본관에게 얼마든지 물어봐도 좋다.","JPN":"もし銃器の組み立て方や\\n構え方、実戦戦闘術について知りたい者がいるならば、\\n本官がいくらでも質問に答えよう。","ENG":"If any of you are curious about firearm assembly, phage techniques, or field combat, feel free to come ask me about them.","TWN":"如果大家對組裝槍械，野戰戰法有興趣的話，請儘管來問本官。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"특히 이 몸이 개발한 근접전투 사격술인 클로즈 쿼터 슈팅 스킬은 용병 업계에서도 소문이 자자한......","JPN":"特に本官が編み出した近接戦闘射撃術、\\nクローズクォーターシューティングスキルは、傭兵業界においても\\n大変評判が……","ENG":"The close-quarter shooting skill I have developed is already well-known amongst mercenaries—","TWN":"特別是本官開發的近戰射擊術：近身四一射擊法，在傭兵界也是很有名的……"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"TEACHER_EXTRA_F_NULL","text":{"KOREA":"흠! 소림 양. 수업을 시작해야하니 그만 들어가서 자리에 앉으세요.","JPN":"おっほん！　ハネダさん、授業を始めますのでそろそろ席についてくださいね。","ENG":"Ahem! Sorim. Class is starting soon. Please go on and take a seat.","TWN":"咳咳，韓蕭林同學。我們要開始上課了，請妳先回到自己的座位上吧。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"앗! 네!","JPN":"あっ、はい！","ENG":"Oh! Yes, of course!","TWN":"啊！是！"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"subtitle","speaker":null,"text":{"KOREA":"1교시: <color=#ffd34c>수학시간</color>     ","JPN":"1時限目：<color=#ffd34c>数学</color>     ","ENG":"1st Period: <color=#ffd34c>Math</color>     ","TWN":"第1節課: <color=#ffd34c>數學課</color>","THA":"คาบที่ 1: <color=#ffd34c>คณิตศาสตร์</color>     ","VTN":"Tiết 1: <color=#ffd34c>Toán</color>","SCN":"第1节课: <color=#ffd34c>数学课</color>     ","DEU":"1. Stunde: <color=#ffd34c>Mathematik</color>     ","FRA":"1re\xA0période\xA0: <color=#ffd34c>Maths</color>     "},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"TEACHER_EXTRA_F_NULL","text":{"KOREA":"자, 이번 문제는 새로 온 친구가 풀어보도록 할까?","JPN":"さて、この問題は、新しいお友達に解いてもらいましょう。","ENG":"Okay, why don't we ask our new friend to solve this problem?","TWN":"那麼，這個問題就由新來的同學解一下吧？"},"stage":{"bg":"CLASS","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};